// ==UserScript==
// @name         Adventure Engine — Bridge + HUD v1.1.4
// @namespace    Violentmonkey Scripts
// @version      1.1.4
// @description  AE bridge + scene HUD + image generation.
// @match        https://novelai.net/*
// @license      MIT
// @run-at       document-start
// @inject-into  page
// @sandbox      raw
// @grant        none
// ==/UserScript==

// =============================================================================
// PART 0.5 — PHANTOM WIDGET ENGINE (STAGE 1 PoC)
// =============================================================================
// [v0.9.95 PHANTOM] Single canonical PhantomManager. The old STAGE-1 PoC stub that
// lived here shadowed the real engine (assigned in init below), so destroy() calls
// hit the stub while spawn() hit the real one - widgets never closed. Forward-declared
// here; assigned once in init. All references now resolve to one object.
var PhantomManager;

// =============================================================================
// PART 0.6 — CYBERTHEME & CYBERICONS (JS Bridge Definition)
// Mirrors CSS design tokens for JavaScript consumption.
// =============================================================================
//
// ┌───────────────────────────────────────────────────────────────────────┐
// │ ICON SOURCE MAP — "I see an icon on screen, where do I change it?"     │
// │ [v1.1.4] Keyed by symbol name, not line number (line numbers drift).  │
// └───────────────────────────────────────────────────────────────────────┘
// Almost everything routes through the resolver, so a swap is usually just a
// rename. The exceptions (raw emoji sinks) are listed at the bottom.
//
// WHERE ICONS ARE DEFINED (edit the value here to restyle an icon globally):
//   • CyberIcons              — stroke icons (24x24). Base set + an
//                               Object.assign(...) extension further down.
//   • AEFillIcons             — hand-tuned fill icons (512x512). Use when you
//                               need a fixed two-tone/gradient color.
//   • AERawIcons              — PASTE-AND-GO fill icons. Drop raw <svg> source
//                               in, no reformatting. ← easiest place to add.
//   • AE_WITCH_ICONS /
//     AE_SAKURA_ICONS         — extra stroke paths a theme draws from.
//
// WHERE ON-SCREEN ICONS ARE CHOSEN (change the NAME string to swap):
//   • Tab bar / close / settings / Theme Forge — in AE_HTML, via
//     getCyberIconHTML('bookOpen'|'mapPin'|'userScan'|'dpad'|'crown'|
//     'close'|'settings'). Change the name arg (or redefine that entry).
//   • Map nodes by type       — MAP_ICONS[node.type] → name. Per-node override:
//                               engine's node.icon field (any library name).
//   • Entity rows by type     — _AE_TYPE_ICONS[type] → name. Per-entity
//                               override: engine's entity `icon` field.
//   • Per-theme re-skins       — AE_THEME_ICONS['theme-x'] = { key: path }
//                               or { key: { fill:'aeKey' } }. Only list keys
//                               that differ from the default.
//   • Phantom tray             — createCyberIcon('mapPin'|'userScan'|'dpad'|
//                               'crown'). (fallbackEmoji is only shown if the
//                               SVG node fails — not the primary.)
//
// HOW A NAME RESOLVES (the hub — read this once and you'll never guess):
//   _aeIconRenderKind(name) precedence:
//     active-theme override → CyberIcons → AEFillIcons → AERawIcons.
//   _aeIconExists(name) is the gate; getCyberIconHTML / createCyberIcon /
//   $.svg(name) are the renderers. A raw entry NEVER shadows a same-named
//   stroke or hand-tuned fill icon — so to override a name a stroke icon
//   already owns, use a distinct key (e.g. teleportUser, not teleport).
//
// RAW SINKS — NOT name-routed. To turn these into SVGs, replace the emoji
// literal with a library name at the spot itself (grep the glyph):
//   • Map edge markers passed to midIcon(): '🔒' (gated), '🚢' (needs
//     vehicle), '⛽️' (resource-cost fallback; engine resourceIcon can be a
//     name instead). midIcon tries $.svg(icon) first, so a name renders SVG.
//   • Fallback glyphs: fallbackEmoji in the phantom tray, and the
//     `.textContent = ... || '?'` fallbacks in map-node / entity rendering.
//   • Entity-block header: hIcon.textContent = icon (renders the passed value
//     as text, not SVG).
// =============================================================================
var CyberIcons = {
    close: '<path d="M18 6L6 18M6 6l12 12"/>',
    speech: '<path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" stroke-linecap="round" stroke-linejoin="round"/>',
    dice: '<rect x="3" y="3" width="18" height="18" rx="2" ry="2" stroke-linecap="round" stroke-linejoin="round"/><circle cx="9" cy="9" r="1.2"/><circle cx="15" cy="15" r="1.2"/><circle cx="15" cy="9" r="1.2"/><circle cx="9" cy="15" r="1.2"/><circle cx="12" cy="12" r="1.2"/>',
    settings: '<path d="M12.22 2h-.44a2 2 0 00-2 2v.18a2 2 0 01-1 1.73l-.43.25a2 2 0 01-2 0l-.15-.08a2 2 0 00-2.73.73l-.22.38a2 2 0 00.73 2.73l.15.1a2 2 0 011 1.72v.51a2 2 0 01-1 1.74l-.15.09a2 2 0 00-.73 2.73l.22.38a2 2 0 002.73.73l.15-.08a2 2 0 012 0l.43.25a2 2 0 011 1.73V20a2 2 0 002 2h.44a2 2 0 002-2v-.18a2 2 0 011-1.73l.43-.25a2 2 0 012 0l.15.08a2 2 0 002.73-.73l.22-.39a2 2 0 00-.73-2.73l-.15-.08a2 2 0 01-1-1.74v-.5a2 2 0 011-1.74l.15-.1a2 2 0 00.73-2.73l-.22-.38a2 2 0 00-2.73-.73l-.15.08a2 2 0 01-2 0l-.43-.25a2 2 0 01-1-1.73V4a2 2 0 00-2-2z"/><circle cx="12" cy="12" r="3"/>',
    inspect: '<circle cx="11" cy="11" r="8"/><path d="M21 21l-4.3-4.3"/>',
    action: '<path d="M12 2v20M2 12h20M12 2l3 3M12 2L9 5M12 22l3-3M12 22l-3-3M2 12l3-3M2 12l3 3M22 12l-3-3M22 12l-3 3"/>',
    arrowLeft: '<path d="M19 12H5M12 19l-7-7 7-7"/>',
    idCard: '<rect x="3" y="4" width="18" height="16" rx="2"/><path d="M7 8h10M7 12h10M7 16h6"/>',
    camera: '<path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/><circle cx="12" cy="13" r="4"/>',
    mapPin: '<path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/>',
    userScan: '<path d="M3 7V5a2 2 0 0 1 2-2h2M17 3h2a2 2 0 0 1 2 2v2M21 17v2a2 2 0 0 1-2 2h-2M7 21H5a2 2 0 0 1-2-2v-2M16 11a4 4 0 1 1-8 0 4 4 0 0 1 8 0zM6 21v-1a6 6 0 0 1 12 0v1"/>',
    dpad: '<path d="M12 2v20M2 12h20M12 2l3 3M12 2L9 5M12 22l3-3M12 22l-3-3M2 12l3-3M2 12l3 3M22 12l-3-3M22 12l-3 3"/>',
    crown: '<path d="M2 4l3 12h14l3-12-6 7-4-7-4 7-6-7z"/>',
    bolt: '<path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/>',
    target: '<circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="6"/><circle cx="12" cy="12" r="2"/>',
    focus: '<circle cx="12" cy="12" r="3"/><path d="M3 12h3M18 12h3M12 3v3M12 18v3"/>',
    bookOpen: '<path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z"/><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z"/>',
    wrench: '<path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z" stroke-linecap="round" stroke-linejoin="round"/>'
};

// =============================================================================
// AEFillIcons — custom fill-based SVG icons. Unlike CyberIcons (which are 24x24
// stroke paths that inherit currentColor), these are 512x512 filled icons.
// Each entry is the normalized inner <path> / <g> content to inject into a 512
// viewBox SVG. The helper aeCreateFillIcon() builds the DOM element.
//
// [vNEXT] THIS REGISTRY IS NOW WIRED INTO THE SAME RESOLVER AS CyberIcons.
// Any existing getCyberIconHTML(name)/createCyberIcon(name)/$.svg(name) call
// site, anywhere in the file, will pick up an AEFillIcons entry automatically
// if no stroke icon (CyberIcons or an active theme's override) already
// answers to that same name — see _aeIconRenderKind() below CyberIcons. That
// means you can upgrade an existing icon in place just by adding a
// same-named entry here, OR give one theme its own swap via a
// { fill: 'yourKey' } entry in AE_THEME_ICONS (see that section for the
// Witch's Hollow 'gem' -> littleMushrooms example). You don't need to touch
// any call site or the theme layer unless you specifically want a per-theme
// override rather than a global one.
//
// HOW TO ADD YOUR OWN ICON:
//   ⇒ EASIEST: skip all of this and just paste raw SVG source into AERawIcons
//     (defined right below this registry). It strips wrappers, rescales any
//     viewBox, and recolors to currentColor for you — no manual prep. Only
//     hand-edit AEFillIcons directly when you need a fixed second (two-tone)
//     color that the auto-recolor would flatten. The manual steps follow:
//   1. Find a 512x512 (or any size — non-512 gets auto-rescaled) icon at
//      SVGRepo, game-icons.net, etc.
//   2. Convert it with the AEFillIcons Converter tool (paste the SVG source,
//      it strips the SVGRepo wrapper junk, rescales to 512x512, and detects
//      single/two/multi-color automatically) — or do it by hand:
//      a. Delete everything outside <g id="SVGRepo_iconCarrier"> (the
//         bgCarrier/tracerCarrier groups add nothing).
//      b. Find every  fill="#000000"  or  fill="black"  attribute.
//         — ONE color:  replace ALL of them with  fill="currentColor"
//         — TWO colors: primary -> fill="currentColor", secondary ->
//           fill="var(--ae-icon-accent, currentColor)" (or any CSS var).
//           A <linearGradient> can stay as-is (static) or get flattened to
//           currentColor/var() the same way.
//      c. If the source viewBox isn't 512x512, wrap the content in
//         <g transform="scale(512/N)"> where N is the source's width/height.
//   3. Paste ONLY the inner content (path/g content, NOT the outer <svg> tag)
//      as a new string property in AEFillIcons below.
//   4. Use it: give an entity's icon field this key directly, reference it
//      from AE_THEME_ICONS as { fill: 'yourKey' }, add a same-named entry to
//      upgrade an existing unthemed icon everywhere, or call
//      aeCreateFillIcon('yourKey', size, color) / aeFillIconHTML(...) directly
//      if you're building something outside the normal icon call sites.
//
// COLOR INHERITANCE:
//   currentColor → follows CSS `color:` on the parent element (ThemeForge works).
//   var(--ae-icon-accent, #fallback) → follows the ThemeForge accent variable.
//   Hardcoded hex (#FFFFFF etc.) → static, ignores theme — fine for two-tone detail.
// =============================================================================
var AEFillIcons = {

    // Sword / character — single color fill.
    // Source: SVGRepo 512x512 sword. fill="#000000" -> fill="currentColor"
    sword: '<path fill="currentColor" d="M329.8 235.69l62.83-82.71 42.86 32.56-62.83 82.75zm-12.86-9.53l66.81-88-45-34.15-66.81 88zm-27.48-97.78l-19.3 39.57 57-75-42.51-32.3-36.24 47.71zm-20.74-73.24l-46.64-35.43-42 55.31 53.67 26.17zm107 235.52l-139-102.71-9.92.91 4.56 2 62.16 138.43-16.52 2.25-57.68-128.5-40-17.7-4-30.84 39.41 19.42 36.36-3.33 17-34.83-110.9-54.09-80.68 112.51L177.6 346.67l-22.7 145.62H341V372.62l35.29-48.93L387 275.77z"/>',

    // Buildings / town — single color fill.
    // Source: SVGRepo 512x512 buildings. fill="#000000" -> fill="currentColor"
    buildings: '<path fill="currentColor" d="M208 80v25h-13v126h18v-71c0-5.5 1.4-10.5 4.3-14.4 3-3.9 7.8-6.5 12.7-6.5 5 0 9.7 2.7 12.7 6.6 2.9 3.9 4.3 8.8 4.3 14.3v71h18v-71c0-5.5 1.4-10.5 4.3-14.4 2.9-3.9 7.7-6.6 12.7-6.6 5 0 9.8 2.7 12.7 6.6 2.9 3.9 4.3 8.9 4.3 14.4v71h18V105h-13V80h-18v25h-21V80h-18v25h-21V80h-18zM16 112v32h9v71h78v-65.9h9V112H94v25H73v-25H55v25H34v-25H16zm384 0v32h9v71h78v-71h9v-32h-18v25h-21v-25h-18v25h-21v-25h-18zm-265 32v25h-14v64h-16v254h110v-81.6c0-17.5 4.4-31.5 11.8-41.4 7.4-9.9 18.2-15.6 29.2-15.6s21.8 5.7 29.2 15.6c7.4 9.9 11.8 23.9 11.8 41.4V487h110V233h-16v-64h-14v-25h-18v25h-24v80H177v-80h-24v-25h-18zm-94 89v254h46V233H41zm384 0v254h46V233h-46zm-290 7h18v48h-18v-48zm224 0h18v48h-18v-48zM135 359h50v50h-50v-50zm192 0h50v50h-50v-50zm-71 7.4c-5 0-10.2 2.3-14.8 8.4-4.6 6.1-8.2 16.1-8.2 30.6V432h46v-26.6c0-14.5-3.6-24.5-8.2-30.6-4.6-6.1-9.8-8.4-14.8-8.4zM153 377v14h14v-14h-14zm192 0v14h14v-14h-14z"/>',

    // Spell Book — TWO color fill. Primary (book body) = currentColor, secondary
    // (star/arc details) = var(--ae-icon-accent, #e8c87c). The linearGradient is
    // converted to a flat currentColor fill so it themes cleanly; keeping the
    // original gradient is also fine — just paste it back if you prefer the static look.
    spellbook: '<path fill="currentColor" d="M162.027,360.441v73.413c0,4.554,5.805,6.479,8.525,2.825l12.645-16.98c0.451-0.605,1.359-0.599,1.801,0.013l11.992,16.577c2.689,3.718,8.564,1.815,8.564-2.772v-73.075H162.027z"/><path fill="currentColor" opacity="0.7" d="M309.645,360.441v113.088c0,3.281,4.313,4.476,5.987,1.653c6.298-10.608,16.825-26.333,27.974-34.318c0.852-0.609,1.365-1.56,1.365-2.607v-77.815H309.645z"/><path fill="currentColor" opacity="0.5" d="M340.555,35.233h46.059c7.661,0,13.872,6.211,13.872,13.872v305.021c0,7.661-6.211,13.872-13.872,13.872h-46.059V35.233z"/><path fill="currentColor" opacity="0.6" d="M268.258,43.615h99.326c8.564,0,15.506,6.943,15.506,15.507v293.369c0,8.564-6.941,15.507-15.506,15.507h-99.326V43.615z"/><path fill="currentColor" d="M129.536,35.233h147.942l24.04,35.087c2.444,3.568,8.002,2.232,8.558-2.057l4.282-33.03h30.595c7.175,0,12.992,5.817,12.992,12.992v306.78c0,7.175-5.817,12.992-12.992,12.992H128.698c-9.49,0-17.183-7.693-17.183-17.184V53.255C111.515,43.302,119.583,35.233,129.536,35.233z"/><path fill="currentColor" opacity="0.85" d="M367.051,79.716v107.243l24.069-99.8c0.915-3.793-1.96-7.443-5.86-7.443H367.051z"/><path fill="var(--ae-icon-accent,#e8c87c)" d="M275.082,201.306l17.881-33.115c1.902-3.522-0.648-7.8-4.652-7.8h-35.32l-13.609-25.202c-1.998-3.7-7.306-3.7-9.304,0l-13.608,25.202h-35.32c-4.003,0-6.554,4.277-4.652,7.8l17.881,33.115l-17.881,33.115c-1.902,3.522,0.649,7.799,4.652,7.799h35.32l13.608,25.203c1.998,3.7,7.307,3.7,9.304,0l13.609-25.203h35.32c4.004,0,6.555-4.276,4.652-7.799L275.082,201.306z M278.787,171.359l-9.938,18.403l-9.938-18.403H278.787z M262.617,201.306l-16.171,29.946h-23.435l-16.17-29.946l16.17-29.946h23.435L262.617,201.306z M234.729,149.658l5.795,10.732h-11.59L234.729,149.658z M190.672,171.359h19.874l-9.937,18.403L190.672,171.359z M190.672,231.252l9.937-18.403l9.937,18.403H190.672z M234.729,252.952l-5.795-10.732h11.59L234.729,252.952z M268.85,212.848l9.938,18.404h-19.875L268.85,212.848z"/><path fill="var(--ae-icon-accent,#e8c87c)" opacity="0.7" d="M159.483,191.128c3.947-29.271,25.252-53.812,53.556-62.25c15.352-4.577,30.036-3.984,43.285-0.009c1.861,0.559,3.824-0.438,4.377-2.301l2.209-7.428c0.538-1.811-0.461-3.758-2.27-4.3c-8.214-2.463-16.907-3.803-25.912-3.803c-22.875,0-43.782,8.536-59.74,22.574c-1.236,1.088-1.549,2.902-0.801,4.369l3.387,6.646l-5.525-3.885c-1.486-1.046-3.546-0.853-4.759,0.501c-14.373,16.035-23.141,37.191-23.141,60.37c0,35,19.964,65.407,49.094,80.482c1.972,1.02,4.397,0.019,5.177-2.061l2.541-6.775c0.671-1.79-0.131-3.756-1.817-4.654C172.321,254.307,154.987,224.47,159.483,191.128z"/><path fill="var(--ae-icon-accent,#e8c87c)" opacity="0.7" d="M282.068,127.492l-5.615,7.279c-0.977,1.266-0.646,3.063,0.678,3.957c20.631,13.947,34.114,37.692,33.535,64.548c-0.773,35.922-32.204,70.089-67.935,73.87c-11.665,1.234-22.825-0.279-33.021-3.864c-1.682-0.592-3.485,0.444-3.74,2.21l-1.316,9.114c-0.194,1.343,0.592,2.657,1.881,3.081c12.25,4.025,25.635,5.523,39.553,3.805c42.821-5.285,76.411-41.149,79.047-84.214c2.04-33.317-14.061-63.08-39.33-80.401C284.605,126.056,282.955,126.342,282.068,127.492z"/>',

    // Little mushrooms — single color fill. Source: SVGRepo 512x512, converted
    // via the AEFillIcons Converter tool (no rescaling needed, already 512x512).
    // Added as the Witch's Hollow theme's 'gem' icon override (see AE_THEME_ICONS)
    // — a nicer toadstool motif than the old 2-path CyberIcons stroke sketch.
    littleMushrooms: '<path d="M171.9 27.96c-3.5 0-7 .32-10.6 1.05-26.1 5.26-42.2 25.9-53.7 54.08-11.61 28.21-17.63 62.81-23.09 91.51-3.97 20.8-8.73 46.2-8.26 68.3.47 22.1 5.79 39.4 20.17 48.6C131.8 314 183.3 313.6 231.7 297c48.3-16.5 92.9-49 114.1-86.2 3.5-6.2 4.7-16.8 2.6-26.5-2.2-9.8-7.4-18.2-13.2-21.7-37-22.2-65.4-60-92.8-89.72-13.8-14.84-27.2-27.6-40.5-35.54-10-5.96-19.7-9.28-30-9.38zM432.1 289.9c-3.5 0-8 .3-12.8 1-9.6 1.4-21 4.3-32.3 8.5-22.6 8.3-44.5 22.3-52.8 37.3-4.2 7.8-1.3 24 5.4 31.9 30.2 35.7 90.8 56.8 135.5 44.7 7.5-2 16.4-12.1 17.3-19.4 2.3-18.5-3.3-42.9-13.6-63.2-10.3-20.2-25.5-35.9-38.9-40-1.5-.4-4.2-.7-7.8-.8zm-168.7 13.8c-8.5 3.9-17.1 7.4-25.9 10.4-16.5 5.6-33.5 9.6-50.4 11.6-.1 1.7-.3 3.3-.4 5-1.3 16.5-2.6 33.4-1.6 47.5 1 14.1 4.4 24.7 10.2 30.3 9.8 9.3 27.4 15.2 44.8 15.4 17.4.2 34.2-5.4 43.1-15 8.8-9.5 10.2-18.8 8-31.6-2.2-12.8-8.9-28.2-16.2-45.1-3.9-9-8-18.6-11.6-28.5zM62.04 345.1c-.7 0-1.39.1-2.07.1-3.62.2-6.92.9-9.73 2.2C37.8 353 25.43 374 21.05 395.8c-2.2 10.9-2.55 21.7-1.02 30.2 1.54 8.5 4.8 13.9 8.54 16.3 1.69 1.1 2.92 1.3 5.55.8 2.64-.4 6.37-2 10.56-4.4 8.39-4.8 18.36-12.8 29.14-18.9 13.54-7.5 28.98-11.6 39.68-16.3 5.4-2.4 9.4-4.8 11.4-6.9 2-2 2.4-2.9 2.1-5.8-1.3-9.9-13.7-25.3-30.14-35.1-11.53-6.8-24.35-10.7-34.85-10.6zm311.06 71.8c-3.9 9-7.1 18.6-8.5 27-1.5 8.5-.8 15.4 1.5 19.3 5 8.4 17 16.1 30.1 19.2 13.2 3.2 26.7 1.7 34.3-3.9 2.7-2 5.3-6.8 6.7-14 1.4-7.2 1.6-16.2 1.1-25-.1-1.6-.2-3.2-.4-4.7-22.2-1.3-44.6-7.6-64.8-17.9zM98.33 428.6c-5.65 2.2-11.06 4.4-15.7 7-5.52 3.1-11.42 7.3-17.56 11.4-1.48 5.5-2.26 12.1-1.71 17.8.7 7.1 3.18 11.8 6.46 13.6 4.62 2.6 13.46 2.3 21.81-1.4 8.34-3.7 15.37-10.5 17.27-16 1.9-5.4.7-14.9-3.5-22.9-1.9-3.7-4.4-7-7.07-9.5z" fill="currentColor"/>'
};

// =============================================================================
// AERawIcons — PASTE-AND-GO icon registry (the low-friction path). [v1.1.4 RAWICONS]
//
// The easiest way to add an icon. Unlike AEFillIcons (which wants pre-cleaned
// 512x512 inner path content), AERawIcons takes the *raw SVG source exactly as
// copied* from SVGRepo, game-icons.net, Iconify, etc. — wrapper <g> scaffold,
// odd viewBox, hardcoded fill and all. It is normalized once, on first use, by
// _aeNormalizeRawSVG() (see below CyberIcons' fill helpers): the SVGRepo
// bg/tracer groups are dropped, the icon carrier is unwrapped, every solid
// fill/stroke is swapped to currentColor (so ThemeForge drives the color), and
// any viewBox other than 0 0 512 512 is uniformly scaled + centered into a 512
// canvas. The result is cached into AEFillIcons under the same key, so it then
// renders through the exact same fill path as everything else.
//
// HOW TO ADD ONE (the whole job):
//   1. Copy the icon's full <svg>...</svg> source.
//   2. Paste it as a backtick string under a new key here.
//   3. Use that key anywhere an icon name is accepted — a map node's `icon`
//      field, an entity icon, $.svg('key'), getCyberIconHTML('key'),
//      createCyberIcon('key'), or a theme override. Done. No reformatting.
// TO SWAP: rename the key, or move a source string to a different key.
//
// PRECEDENCE (see _aeIconRenderKind): theme override → CyberIcons (stroke) →
// AEFillIcons (hand-tuned fill) → AERawIcons. So a raw entry is a safe additive
// layer — it never shadows a same-named stroke or hand-tuned fill icon. If you
// WANT a raw icon to win a name a stroke icon already owns, give it a distinct
// key (e.g. `teleportUser`, not `teleport`) and reference that key.
//
// Colors: solid fills/strokes become currentColor. fill="none" and url(#...)
// gradient refs are left untouched, so two-tone / gradient icons keep detail.
// Need a fixed second color? Hand-tune it in AEFillIcons instead.
//
