// extraClass is appended alongside the base class so fill icons can hook the
// same CSS (e.g. the cyber-pulse-* glow classes) as stroke icons do.
function aeCreateFillIcon(key, size, color, extraClass) {
    size = size || 20;
    color = color || 'currentColor';
    var svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('viewBox', '0 0 512 512');
    svg.setAttribute('width', String(size));
    svg.setAttribute('height', String(size));
    svg.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
    svg.style.color = color;
    svg.style.display = 'inline-block';
    svg.style.verticalAlign = 'middle';
    svg.style.flexShrink = '0';
    if (extraClass) svg.setAttribute('class', extraClass);
    svg.innerHTML = _aeEnsureFillContent(key);
    return svg;
}

// HTML string version — use in template literals or innerHTML contexts.
function aeFillIconHTML(key, size, color, extraClass) {
    size = size || 20;
    color = color || 'currentColor';
    var cls = extraClass ? (' class="' + extraClass + '"') : '';
    return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="' + size + '" height="' + size + '" style="color:' + color + ';display:inline-block;vertical-align:middle;flex-shrink:0;"' + cls + '>' + _aeEnsureFillContent(key) + '</svg>';
}

