const BRIDGE_VERSION    = '1.1.3'; // keep in sync with @version header + @name label above
const PRESET_CACHE_KEY  = 'ae_img_preset_cache';

const DEFAULT_PRESET = {
    width: 832, height: 1216, steps: 23, scale: 7.0,
    qualityTags: 'best quality, amazing quality, masterpiece',
    negativeTags: 'blurry, lowres, bad anatomy, worst quality',
    seed: 0
};

// NAI image API
function getAuthToken() {
    try {
        var s = localStorage.getItem('session');
        if (s) {
            var p = JSON.parse(s);
            var tok = p.token || p.auth_token || p.access_token || p.accessToken;
            if (!tok && p.data) tok = p.data.token || p.data.auth_token || p.data.access_token;
            if (!tok && p.user) tok = p.user.token || p.user.auth_token;
            if (tok && String(tok) !== 'undefined') return 'Bearer ' + tok;
        }
    } catch(_) {}
    return null;
}
function _authDebug() {
    try { return 'LS keys: ' + Object.keys(localStorage).filter(function(k){return /session|token|auth/i.test(k);}).join(', ') || 'none found'; }
    catch(_) { return 'localStorage unavailable'; }
}

// NAITMBridge — provided by the NAI companion extension
const NAITMBridge = window.NAITMBridge || null;

// [v0.9.28] Pinned project assets. Fetched on demand; the background is cached in
