// [v0.9.13 X3] Sends pending player flavor to the engine before an action fires.
// Called by every action-dispatch function. Engine stores it in tempStorage and
// consumes it when writing the next > prompt (inject_narrative or outcomeNote).
function _sendFlavorIfAny() {
    var f = _playerFlavor.trim();
    if (f) { sendToEngine('AE_SET_PLAYER_FLAVOR', { text: f }); }
}
var _bridgeUnsubscribe = null; // bridge.on() cleanup — prevents double-registration on script reinject
var _sectionOpenState  = {};   // collapsible section open/close — persists across HUD re-renders
var _snapTextCollapsed = {};   // [v021] snapshot text collapse state
var _focusedEntityDetail = null; // [v021] focused entity detailed state from B contract
// Inline entity bubbles (items / narratives expand in place in the scene list).
var _entityDetailCache = {};     // entityId -> last detail payload (for instant repaint)
var _openBubbleRenderers = {};   // entityId -> fn(detail) repainting an open bubble body
var _entityBubbleOpen = {};      // entityId -> bool, persists expand state across re-renders

// Map state
var _mapPanX = 0, _mapPanY = 0;
var _mapPanSetup = false; // [v0.9.15] B6: guards window-level pan listeners against re-registration
var _mapGlideTimer = null;
var _mapSelectedId  = null;
var _mapPlayerLocId  = null;   // player’s actual location id
var _mapCurrentGraph = null;   // locationGraph from engine, or null
var _mapInVehicleId       = null;   // set when player's effective location IS a vehicle entity
var _mapOperateMode       = false;  // vehicle operate mode — map shows vehicle world-loc graph
var _mapOperateVehicleId  = null;   // vehicle entity ID when in operate mode
var _mapVehicleWorldLocId = null;   // vehicle's parentId — the world location it is at
var _mapPreOperateGraph   = null;   // saved player graph to restore after operating
var _mapVehicleBaselineGraph = null; // saved vehicle graph for adjacency checks
var _hubActiveSubTab = 0; // [v0.9.102] Persist Hub tab state

// [v0.9.9.12 JOURNAL] Player Journal state, driven by AE_JOURNAL_STATE from the engine.
var _journalState     = { bubbles: [] };  // last payload from engine (bubbles carry precomputed stampLabel)
var _jrnlEditingId    = null;             // bubble id currently in edit mode
var _jrnlEditDraft    = '';               // working text for the bubble being edited
var _jrnlBusy         = false;            // rewrite/compress in flight
var _jrnlShowArchived = false;            // archived list visibility
var _jrnlComposeDraft = '';               // draft for the new-entry box
var _jrnlStampNew     = false;            // stamp-on-add toggle

