    bgLbl.textContent = 'Pane Background';
    bgRow.appendChild(bgLbl);
    
    var bgBtnRow = document.createElement('div');
    bgBtnRow.style.cssText = 'display:flex; gap:4px;';
    
    var uploadBg = $.btn('📁 Upload', 'ghost sm', function() {
        var fi = document.createElement('input');
        fi.type = 'file';
        fi.accept = 'image/*';
        fi.onchange = function() {
            if (!fi.files || !fi.files[0]) return;
            var file = fi.files[0];
            var isWebp = file.type === 'image/webp' || file.name.toLowerCase().endsWith('.webp');
            var fr = new FileReader();
            fr.onload = function(ev) {
                var rawUrl = ev.target.result;
                if (isWebp) {
                    // Preserve original WebP animation frames
                    localStorage.setItem('ae_bottom_bg_data', rawUrl);
                    _updateBottomPaneBackground(document.getElementById('ae-ui-root'), lastSceneState);
                    _showToast('✅ Animated WebP background set');
                } else {
                    // Compress and convert to static WebP
                    _toWebP(rawUrl, 0.85).then(function(webpUrl) {
                        localStorage.setItem('ae_bottom_bg_data', webpUrl);
                        _updateBottomPaneBackground(document.getElementById('ae-ui-root'), lastSceneState);
                        _showToast('✅ Background set (WebP)');
                    }).catch(function(e) {
                        console.error('[AE Theme] Conversion failed:', e);
                    });
                }
            };
            fr.readAsDataURL(file);
        };
        fi.click();
    });
    uploadBg.style.fontSize = '10px';
    
    var clearBg = $.btn('✕ Clear', 'ghost sm', function() {
        localStorage.removeItem('ae_bottom_bg_data');
        _updateBottomPaneBackground(document.getElementById('ae-ui-root'), lastSceneState);
        _showToast('🗑 Custom background cleared');
    });
