    sbDesc.style.cssText = 'font-size:10px; color:var(--ae-text-muted); margin:4px 0 6px 0; line-height:1.4;';
    sbDesc.textContent = 'Default image behind the location banner when no portrait exists. Stored in the module — shared for everyone who loads this story.';
    editorContainer.appendChild(sbDesc);

