    var loading = document.createElement('div'); loading.style.cssText = 'padding:20px;text-align:center;color:var(--ae-text-dim);font-size:12px;'; loading.textContent = 'Loading sources\u2026'; list.appendChild(loading);
    panel.appendChild(list); main.appendChild(panel);
    _wizSources = null;
