    nameIn.addEventListener('blur', _saveProj); nameWrap.appendChild(nameIn); row.appendChild(nameWrap);
    var genreWrap = document.createElement('div'); genreWrap.style.cssText = 'flex:1 1 160px;'; genreWrap.appendChild(_lbl('Genre'));
    var genreIn = document.createElement('input'); genreIn.id = 'ae-setup-genre'; genreIn.type = 'text'; genreIn.placeholder = 'e.g. dark fantasy, cyberpunk noir\u2026'; genreIn.value = proj.genre || ''; genreIn.style.cssText = fieldStyle;
    genreIn.addEventListener('blur', _saveProj); genreWrap.appendChild(genreIn); row.appendChild(genreWrap);
