function _studioSvg(name) {
    var svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('viewBox', '0 0 24 24');
    svg.innerHTML = _STUDIO_SVGS[name] || _STUDIO_SVGS.setup;
    return svg;
}

var _studioRailCollapsed = false;

function _buildStudioRail(ov, activeId) {
    // [v0.9.7.9 WIZARD-REMOVED] Rail reduced to four active tabs.
    // Removed (restore when HUD generation bypass is viable):
    //   { id: 'wizard',   label: 'Wizard Chat', icon: 'wizard'   },
    //   { id: 'memory',   label: 'Memory & AN', icon: 'memory'   },
    //   { id: 'species',  label: 'Species',     icon: 'species'  },
    //   { id: 'factions', label: 'Factions',    icon: 'factions' },
    //   { id: 'intro',    label: 'Intro',       icon: 'intro'    },
    //   { id: 'drama',    label: 'Drama',       icon: 'drama'    },
    var RAIL_TABS = [
        { id: 'setup',      label: 'Setup',          icon: 'setup' },
        null,
        { id: 'locations',  label: 'Locations',      icon: 'locations' },
        { id: 'characters', label: 'Characters',     icon: 'characters' },
        { id: 'gallery',    label: 'Image Gallery',  icon: 'gallery' },
        null,
        { id: 'help',       label: 'Help & Rules',   icon: 'help' }
    ];
    var rail = document.createElement('div');
    rail.className = 'ae-rail' + (_studioRailCollapsed ? ' collapsed' : '');
    rail.id = 'ae-studio-rail';

    // Collapse toggle at top
    var colBtn = document.createElement('button');
    colBtn.className = 'ae-rail-collapse'; colBtn.title = 'Collapse navigation';
    colBtn.appendChild(_studioSvg('collapse'));
    colBtn.addEventListener('click', function() {
        _studioRailCollapsed = true;
        rail.classList.add('collapsed');
        var sb = document.getElementById('ae-rail-show-btn');
        if (sb) sb.classList.add('visible');
    });
    rail.appendChild(colBtn);

    // Section buttons
    RAIL_TABS.forEach(function(t) {
        if (!t) { var sep = document.createElement('div'); sep.className = 'ae-rail-sep'; rail.appendChild(sep); return; }
        var btn = document.createElement('button');
        btn.className = 'ae-rail-btn' + (t.id === activeId ? ' active' : '');
        btn.title = t.label;
        btn.appendChild(_studioSvg(t.icon));
        btn.addEventListener('click', function() {
            _galleryActiveTab = t.id;
            _renderGalleryGrid(ov);
        });
        rail.appendChild(btn);
    });
    return rail;
}

function _buildStudioTopbar(ov, title, srcChatsForTopbar, activeId) {
    // srcChatsForTopbar: null = hide chips; [] = show chips (possibly empty)
    var bar = document.createElement('div'); bar.className = 'ae-studio-topbar';

    // Show-rail button (only visible when rail is collapsed)
    var showRailBtn = document.createElement('button');
    showRailBtn.className = 'ae-rail-show-btn' + (_studioRailCollapsed ? ' visible' : '');
    showRailBtn.id = 'ae-rail-show-btn'; showRailBtn.title = 'Show navigation';
    showRailBtn.appendChild(_studioSvg('expand'));
    showRailBtn.addEventListener('click', function() {
        _studioRailCollapsed = false;
        var rail = document.getElementById('ae-studio-rail');
        if (rail) rail.classList.remove('collapsed');
        showRailBtn.classList.remove('visible');
    });
    bar.appendChild(showRailBtn);

    var titleEl = document.createElement('span'); titleEl.className = 'ae-studio-topbar-title'; titleEl.textContent = title; bar.appendChild(titleEl);

    // Source chips (for entity/gen tabs)
    if (srcChatsForTopbar !== null) {
        var srcArea = document.createElement('div'); srcArea.className = 'ae-studio-topbar-sources';
        if (srcChatsForTopbar.length > 0) {
            var lbl = document.createElement('span'); lbl.className = 'ae-src-label'; lbl.textContent = 'Sources'; srcArea.appendChild(lbl);
            srcChatsForTopbar.forEach(function(c) {
                var on = !!_wizEntitySrc[c.id];
                var chip = document.createElement('button'); chip.className = 'ae-src-chip' + (on ? ' on' : ''); chip.type = 'button'; chip.textContent = c.title;
                chip.addEventListener('click', function() {
                    _wizEntitySrc[c.id] = !_wizEntitySrc[c.id];
                    chip.classList.toggle('on', !!_wizEntitySrc[c.id]);
                });
                srcArea.appendChild(chip);
            });
        } else {
            var noSrc = document.createElement('span'); noSrc.style.cssText = 'font-size:11px;color:var(--ae-text-dim);font-style:italic;'; noSrc.textContent = 'No wizard chats — start one'; srcArea.appendChild(noSrc);
        }
        bar.appendChild(srcArea);
    } else {
        var spacer = document.createElement('div'); spacer.style.flex = '1'; bar.appendChild(spacer);
    }

    // Close button
    var end = document.createElement('div'); end.className = 'ae-studio-topbar-end';
    // [v0.9.7.6] Tab-level Sync to Lorebook for lorebook-backed kinds. One message;
    // the engine create-or-updates every entry of this kind and toasts a summary.
    if (['species', 'factions', 'characters', 'locations'].indexOf(activeId) >= 0) {
        var syncBtn = document.createElement('button'); syncBtn.className = 'ae-btn ghost sm';
        syncBtn.title = 'Create or update NAI lorebook entries for every item in this tab';
        var _syncIc = $.svg('book', 14);
        syncBtn.innerHTML = (_syncIc ? _syncIc.outerHTML + ' ' : '') + 'Sync to Lorebook';
        syncBtn.addEventListener('click', function() {
            syncBtn.disabled = true; var _syncLbl = syncBtn.innerHTML; syncBtn.innerHTML = 'Syncing\u2026';
            _studioNotice('Syncing ' + activeId + ' to lorebook\u2026', 'info');
            sendToEngine('AE_SYNC_LOREBOOK', { kind: activeId });
            setTimeout(function() { syncBtn.disabled = false; syncBtn.innerHTML = _syncLbl; }, 2500);
        });
        end.appendChild(syncBtn);
    }
    var closeBtn = document.createElement('button'); closeBtn.className = 'ae-btn ghost sm'; closeBtn.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" stroke-width="2" fill="none"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>'; closeBtn.title = 'Close studio';
    closeBtn.addEventListener('click', function() { ov.style.display = 'none'; });
    end.appendChild(closeBtn); bar.appendChild(end);
    return bar;
}

// [v0.9.7.5 STUDIO-RAIL] Wizard is now a rail tab — FAB/bubble removed.

// [v0.9.8.1] Image Gallery tab renderer.
// Reads the nai_illustrator images store and displays records scoped to the
// active story (activeStoryId). Falls back to ALL records when the story has no
// stamped images (i.e. pre-v0.9.8.0 images or the storyId is blank). A toggle
// lets the user flip between scoped and all-stories views.
// Per-card actions: click = lightbox, ↓ PNG = download, ✏️ = Edit/Regenerate, 🗑 = delete.

// -----------------------------------------------------------------------------
// SECTION 21d — IMAGE GALLERY TAB
// -----------------------------------------------------------------------------

var _imgGalleryShowAll = false;

function _renderGalleryImageTab(host) {
    host.innerHTML = '';

    // -- header row: scope toggle + count --
    var hrow = document.createElement('div');
    hrow.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:12px;flex-shrink:0;';
    var scopeLbl = document.createElement('span');
    scopeLbl.style.cssText = 'font-size:12px;color:var(--ae-text-muted);flex:1;';
    hrow.appendChild(scopeLbl);
    var toggleBtn = $.btn('Show all stories', 'ghost sm', function() {
        _imgGalleryShowAll = !_imgGalleryShowAll;
        toggleBtn.textContent = _imgGalleryShowAll ? 'This story only' : 'Show all stories';
        _imgGalleryRepaint();
    });
    toggleBtn.textContent = _imgGalleryShowAll ? 'This story only' : 'Show all stories';
    hrow.appendChild(toggleBtn);
    host.appendChild(hrow);

    // -- image grid --
    var grid = document.createElement('div');
    // [v0.9.9.9] Plain-height grid: the host .ae-studio-content already scrolls,
    // so the grid must NOT be its own flex:1 scroll region. The old
    // flex:1;min-height:0;overflow-y:auto nested a second scroller inside the
    // scrolling host, which collapsed each grid row to a sliver (images rendered
    // as thin horizontal bands that wouldn't scroll). Matches the sibling
    // location/visualization grids, which lay out correctly.
    grid.style.cssText = 'display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:8px;align-content:start;grid-auto-rows:max-content;';
    host.appendChild(grid);

    var loadingEl = document.createElement('div');
    loadingEl.style.cssText = 'grid-column:1/-1;text-align:center;padding:40px;color:var(--ae-text-dim);font-size:13px;';
    loadingEl.textContent = 'Loading images…';
    grid.appendChild(loadingEl);

    var _allRecs = [];

    // [v0.9.9.9] Effective story id. activeStoryId is only populated by an
    // inbound STORY_ID_SYNC message; if that hasn't arrived when the gallery
    // opens, it's blank and the old `!storyId` short-circuit forced ALL images
    // regardless of the toggle (so "This story only" did nothing). Fall back to
    // the newest stamped record's storyId — records are saved with the story id
    // that was known at generation time and sorted newest-first — so scoping
    // still works. Only truly falls back to "all" when no record carries a
    // storyId (pre-stamp images).
    function _effectiveStoryId() {
        if (activeStoryId) return activeStoryId;
        for (var i = 0; i < _allRecs.length; i++) {
            if (_allRecs[i] && _allRecs[i].storyId) return _allRecs[i].storyId;
        }
        return '';
    }

    function _imgGalleryRepaint() {
        grid.innerHTML = '';
        var storyId = _effectiveStoryId();
        var recs = _imgGalleryShowAll || !storyId
            ? _allRecs
            : _allRecs.filter(function(r) { return (r.storyId || '') === storyId; });

        // Count for scope label
        var scopedCount = storyId ? _allRecs.filter(function(r) { return (r.storyId || '') === storyId; }).length : _allRecs.length;
        scopeLbl.textContent = storyId
            ? (scopedCount + ' image' + (scopedCount !== 1 ? 's' : '') + ' in this story')
            : (_allRecs.length + ' image' + (_allRecs.length !== 1 ? 's' : '') + ' total');

        if (!recs.length) {
            var empty = document.createElement('div');
            empty.style.cssText = 'grid-column:1/-1;text-align:center;padding:48px 20px;color:var(--ae-text-dim);font-size:13px;line-height:1.5;';
            empty.textContent = _imgGalleryShowAll
                ? 'No images saved yet. Generate one from the Image Studio (camera button on the left tray).'
                : 'No images for this story yet. Use the Image Studio to generate some, or tap “Show all stories” to browse older images.';
            grid.appendChild(empty); return;
        }

        recs.forEach(function(rec) {
            if (!rec.dataUrl) return;
            var card = document.createElement('div');
            card.style.cssText = 'position:relative;border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-md);overflow:hidden;background:var(--ae-bg-raised);display:flex;flex-direction:column;transition:border-color 0.15s;';
            card.addEventListener('mouseenter', function() { card.style.borderColor = 'var(--ae-accent)'; });
            card.addEventListener('mouseleave', function() { card.style.borderColor = 'var(--ae-bg-border)'; });

            // -- Thumbnail (click = lightbox) --
            var thumb = document.createElement('img');
            thumb.src = rec.dataUrl;
            thumb.style.cssText = 'width:100%;aspect-ratio:1/1;object-fit:cover;display:block;cursor:pointer;';
            thumb.setAttribute('data-nai-uuid', rec.uuid);
            thumb.addEventListener('click', function() { _galleryLightbox(rec.dataUrl, (rec.prompt || '').slice(0, 120)); });
            card.appendChild(thumb);

            // -- Prompt snippet --
            if (rec.prompt) {
                var snip = document.createElement('div');
                snip.style.cssText = 'font-size:9px;color:var(--ae-text-dim);padding:4px 5px;line-height:1.3;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;';
                snip.textContent = rec.prompt;
                card.appendChild(snip);
            }

            // -- Action row: download, edit/regen, delete --
            var acts = document.createElement('div');
            acts.style.cssText = 'display:flex;gap:2px;padding:3px 4px;background:var(--ae-bg-panel);border-top:1px solid var(--ae-bg-border);';

            var dlBtn = $.btn('⬇️', 'ghost sm', function() {
                var a = document.createElement('a'); a.href = rec.dataUrl;
                a.download = 'ae-' + String(rec.uuid).slice(0, 8) + '.png';
                document.body.appendChild(a); a.click(); document.body.removeChild(a);
            });
            dlBtn.title = 'Download PNG'; dlBtn.style.flex = '1 1 0';

            var editBtn = $.btn('✏️', 'ghost sm', function() { openPromptEditor(rec.uuid); });
            editBtn.title = 'Edit / Regenerate'; editBtn.style.flex = '1 1 0';

            var delBtn = $.btn('🗑', 'ghost sm', function() {
                if (!confirm('Delete this image? This cannot be undone.')) return;
                dbDelete(rec.uuid).then(function() {
                    _allRecs = _allRecs.filter(function(r) { return r.uuid !== rec.uuid; });
                    imgCache.delete(rec.uuid);
                    _imgGalleryRepaint();
                });
            });
            delBtn.title = 'Delete image'; delBtn.style.flex = '1 1 0';

            acts.appendChild(dlBtn); acts.appendChild(editBtn); acts.appendChild(delBtn);
            card.appendChild(acts);
            grid.appendChild(card);
        });
    }

    // Load records then paint
    dbGetAll().then(function(recs) {
        // Sort newest-first
        _allRecs = (recs || []).slice().sort(function(a, b) { return (b.ts || 0) - (a.ts || 0); });
        _imgGalleryRepaint();
    });
}

