// =============================================================================
// SECTION 22 — IMAGE PRESETS PANEL
// 5 preset slots (from engine api.v1.storage). Navigator < Preset N > + active star.
// Save -> AE_SAVE_PRESET engine message. Set active -> AE_SET_ACTIVE_PRESET.
// All data also cached in localStorage for offline / pre-handshake access.
// =============================================================================

var _presetsOverlay = null;
var _presetEditIdx  = 0;

function _ensurePresetsLoaded() {
    if (_aeAllPresets && _aeAllPresets.length === 5) return;  // engine already synced
    try { var raw = localStorage.getItem(_AE_PRESETS_LS_KEY); if (raw) { var p = JSON.parse(raw); if (Array.isArray(p.presets) && p.presets.length === 5) { _aeAllPresets = p.presets; _aeActivePresetIdx = p.activeIndex || 0; return; } } } catch(_) {}
    _aeAllPresets = Array.from({ length: 5 }, function(_, i) { return { width: 832, height: 1216, steps: 23, scale: 7.0, qualityTags: i === 0 ? (currentPreset.qualityTags || 'best quality, amazing quality, masterpiece') : '', negativeTags: i === 0 ? (currentPreset.negativeTags || 'blurry, lowres, bad anatomy, worst quality') : '' }; });
    _aeActivePresetIdx = 0;
}

function showPresetsPanel() {
    _ensurePresetsLoaded();
    if (_presetsOverlay && document.body.contains(_presetsOverlay)) { _presetsOverlay.style.display = 'flex'; } else {
        var ov = document.createElement('div'); ov.id = 'ae-presets-overlay';
        ov.style.cssText = 'position:fixed;inset:0;z-index:99998;background:var(--ae-bg-base);display:flex;flex-direction:column;font-family:var(--ae-font-sans);color:var(--ae-text-main);';
        _presetsOverlay = ov; document.body.appendChild(ov);
    }
    _renderPresetsContent();
}

function _renderPresetsContent() {
    var ov = _presetsOverlay; if (!ov) return;
    ov.innerHTML = '';
    // Header
    var hdr = document.createElement('div'); hdr.style.cssText = 'display:flex;align-items:center;padding:12px 16px;background:var(--ae-bg-panel);border-bottom:1px solid var(--ae-bg-border);gap:10px;flex-shrink:0;';
    var ht = document.createElement('span'); ht.textContent = '🎨 Image Presets'; ht.style.cssText = 'font-size:15px;font-weight:bold;color:var(--ae-accent);flex:1;'; hdr.appendChild(ht);
    hdr.appendChild($.btn('\u2715', 'ghost sm', function() { ov.style.display = 'none'; })); ov.appendChild(hdr);
    _buildPresetsBody(ov, _renderPresetsContent);
}

// [v0.9.21 GAL3] Builds the preset slot navigator + form into `container`.
// `rerender` is the callback used to redraw after slot/active changes (so the
// standalone overlay and the gallery tab each redraw themselves correctly).
function _buildPresetsBody(container, rerender, embedded) {
    // embedded=true: no internal scroll, flows with parent container.
    _ensurePresetsLoaded();
    var ov = container;
    var slotBar = document.createElement('div'); slotBar.style.cssText = embedded
        ? 'display:flex;align-items:center;justify-content:center;gap:6px;padding:10px 0;border-bottom:1px solid var(--ae-bg-border);margin-bottom:4px;'
        : 'display:flex;align-items:center;justify-content:center;gap:6px;padding:10px 16px;background:var(--ae-bg-panel);border-bottom:1px solid var(--ae-bg-border);flex-shrink:0;';
    slotBar.appendChild($.btn('\u25c4', 'ghost sm', function() { if (_presetEditIdx > 0) { _presetEditIdx--; rerender(); } }));
    var isActive = (_presetEditIdx === _aeActivePresetIdx);
    var slotLbl = document.createElement('span'); slotLbl.style.cssText = 'font-size:14px;font-weight:bold;color:var(--ae-text-main);min-width:90px;text-align:center;'; slotLbl.textContent = 'Preset ' + (_presetEditIdx + 1) + (isActive ? ' \u2605' : ''); slotBar.appendChild(slotLbl);
    slotBar.appendChild($.btn('\u25ba', 'ghost sm', function() { if (_presetEditIdx < 4) { _presetEditIdx++; rerender(); } }));
    var sep = document.createElement('span'); sep.style.cssText = 'color:var(--ae-bg-border-hi);'; sep.textContent = '|'; slotBar.appendChild(sep);
    slotBar.appendChild($.btn(isActive ? '\u2605 Active' : '\u2606 Set Active', isActive ? 'primary sm' : 'ghost sm', function() {
        _aeActivePresetIdx = _presetEditIdx;
        var p = _aeAllPresets[_presetEditIdx] || {};
        currentPreset = Object.assign({}, currentPreset, { qualityTags: p.qualityTags || currentPreset.qualityTags, negativeTags: p.negativeTags || currentPreset.negativeTags, steps: p.steps || currentPreset.steps, scale: p.scale || currentPreset.scale });
        try { localStorage.setItem(_AE_PRESETS_LS_KEY, JSON.stringify({ presets: _aeAllPresets, activeIndex: _aeActivePresetIdx })); } catch(_) {}
        sendToEngine('AE_SET_ACTIVE_PRESET', { index: _presetEditIdx }); rerender();
    })); ov.appendChild(slotBar);
    // Form
    var form = document.createElement('div'); form.style.cssText = embedded ? 'padding:0;display:flex;flex-direction:column;gap:12px;' : 'flex:1;overflow-y:auto;padding:16px;display:flex;flex-direction:column;gap:12px;min-height:0;'; ov.appendChild(form);
    if (!_aeAllPresets[_presetEditIdx]) _aeAllPresets[_presetEditIdx] = { width:832,height:1216,steps:23,scale:7.0,qualityTags:'',negativeTags:'' };
    var preset = _aeAllPresets[_presetEditIdx];
    // Resolution
    var rl = document.createElement('div'); rl.style.cssText = 'font-size:11px;color:var(--ae-text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px;'; rl.textContent = 'Scene Resolution'; form.appendChild(rl);
    var rRow = document.createElement('div'); rRow.style.cssText = 'display:flex;gap:6px;'; form.appendChild(rRow);
    [{l:'Portrait',w:832,h:1216},{l:'Square',w:1024,h:1024},{l:'Landscape',w:1216,h:832}].forEach(function(sz) {
        var m = preset.width === sz.w && preset.height === sz.h;
        var b = $.btn(sz.l + '\n' + sz.w + '\xd7' + sz.h, (m?'primary':'ghost') + ' sm', function() { preset.width = sz.w; preset.height = sz.h; rRow.querySelectorAll('button').forEach(function(bb){bb.className=bb.className.replace('primary','ghost');}); b.className=b.className.replace('ghost','primary'); });
        b.style.cssText += 'flex:1;white-space:pre;font-size:10px;line-height:1.4;text-align:center;'; rRow.appendChild(b);
    });
    // Steps + Scale
    function _nf(lbl, key, min, max, step, fl) {
        var w = document.createElement('div'); w.style.cssText = 'display:flex;align-items:center;gap:10px;';
        var l = document.createElement('div'); l.style.cssText = 'font-size:12px;color:var(--ae-text-muted);min-width:120px;'; l.textContent = lbl;
        var i = document.createElement('input'); i.type = 'number'; i.min = String(min); i.max = String(max); i.step = String(step||1); i.value = String(preset[key]||0);
        i.style.cssText = 'flex:1;background:var(--ae-bg-raised);border:1px solid var(--ae-bg-border);color:var(--ae-text-main);padding:7px 9px;border-radius:var(--ae-radius-sm);font-family:var(--ae-font-sans);font-size:13px;'; i.addEventListener('input', function() { preset[key] = fl ? parseFloat(i.value)||0 : parseInt(i.value,10)||0; }); w.appendChild(l); w.appendChild(i); form.appendChild(w);
    }
    _nf('Steps (max 28)', 'steps', 1, 28, 1, false); _nf('Guidance Scale', 'scale', 1, 15, 0.5, true);
    // Quality + UC textareas
    function _tf(lbl, key, ph) {
        var w = document.createElement('div');
        var l = document.createElement('div'); l.style.cssText = 'font-size:11px;color:var(--ae-text-muted);margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px;'; l.textContent = lbl;
        var ta = document.createElement('textarea'); ta.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-raised);border:1px solid var(--ae-bg-border);color:var(--ae-text-main);padding:7px 9px;border-radius:var(--ae-radius-sm);font-family:var(--ae-font-sans);font-size:12px;resize:vertical;min-height:62px;'; ta.placeholder = ph||''; ta.value = preset[key]||''; ta.addEventListener('input', function() { preset[key] = ta.value; }); w.appendChild(l); w.appendChild(ta); form.appendChild(w);
    }
    _tf('Quality & Style Tags', 'qualityTags', 'best quality, amazing quality, masterpiece\u2026');
    _tf('Undesired Content', 'negativeTags', 'blurry, lowres, bad anatomy, worst quality\u2026');
    // Save button
    var sv = $.btn('💾 Save Preset ' + (_presetEditIdx + 1), 'primary', function() {
        _aeAllPresets[_presetEditIdx] = preset;
        if (_presetEditIdx === _aeActivePresetIdx) { currentPreset = Object.assign({}, currentPreset, { qualityTags: preset.qualityTags, negativeTags: preset.negativeTags, steps: preset.steps, scale: preset.scale }); }
        try { localStorage.setItem(_AE_PRESETS_LS_KEY, JSON.stringify({ presets: _aeAllPresets, activeIndex: _aeActivePresetIdx })); } catch(_) {}
        sendToEngine('AE_SAVE_PRESET', { index: _presetEditIdx, preset: { width: preset.width, height: preset.height, steps: preset.steps, scale: preset.scale, qualityTags: preset.qualityTags, negativeTags: preset.negativeTags } });
        _showToast('\u2713 Preset ' + (_presetEditIdx + 1) + ' saved');
    }); sv.style.width = '100%'; form.appendChild(sv);
}

